const cfg = $('Config').first().json;
const alert = $('Wazuh Alert Webhook').first().json.body;

// Core alert fields
const level = parseInt(alert?.rule?.level ?? 0);
const description = alert?.rule?.description ?? 'Unknown rule';
const agentName = alert?.agent?.name ?? 'unknown';
const agentIp = alert?.agent?.ip ?? 'N/A';
const srcIp = alert?.data?.srcip ?? null;
const dstUser = alert?.data?.dstuser ?? null;
const srcUser = alert?.data?.srcuser ?? null;
const command = alert?.data?.command ?? null;
const groups = Array.isArray(alert?.rule?.groups)
  ? alert.rule.groups.join(', ')
  : (alert?.rule?.groups ?? 'N/A');
const ruleId = alert?.rule?.id ?? 'N/A';
const location = alert?.location ?? 'N/A';
const rawTs = alert?.timestamp ?? new Date().toISOString();
const tz = cfg.timezone ?? 'America/New_York';
const ts = new Date(rawTs).toLocaleString('en-US', { timeZone: tz, hour12: false });
const isCritical = level >= (cfg.criticalLevel ?? 12);

// ============================================================
// Infrastructure context: pulled LIVE from an updatable data store via the
// 'Load Infra Context' node (Postgres by default; swap for HTTP/JSON or Google
// Sheets - see dynamic-infrastructure-context.md). The store returns a single
// { context } string. If it is unreachable we fall back to a short built-in
// summary so an alert is never blocked. CUSTOMIZE the fallback for your network.
// ============================================================
let infraContext = null;
try {
  const ctx = $('Load Infra Context').first().json.context;
  if (ctx && String(ctx).trim()) infraContext = String(ctx).trim();
} catch (e) { infraContext = null; }
if (!infraContext) {
  infraContext = `Infrastructure context (fallback - dynamic store unavailable; replace with YOUR baseline):
- 3-node home lab on 10.0.0.0/24; admin over a mesh VPN, only selected services exposed via reverse proxy / tunnel
- Key hosts: vector-db (10.0.0.20), postgres (10.0.0.21), automation / n8n (10.0.0.22), siem / wazuh (10.0.0.30)
- Active response disabled, monitoring only`;
}
// ============================================================

const systemPrompt = `You are a security analyst reviewing a Wazuh SIEM alert. Respond ONLY with a valid JSON object, no text outside the JSON, no markdown code blocks.

${infraContext}

Response schema (all fields required):
{
  "risk_level": "low|medium|high|critical",
  "likely_cause": "one sentence, most probable explanation given this specific infrastructure",
  "is_likely_false_positive": true or false,
  "fp_reason": "if false positive, brief reason; otherwise empty string",
  "recommended_action": ["action 1", "action 2"],
  "investigate_commands": ["bash command 1", "bash command 2"]
}`;

const userPrompt = `Analyze this Wazuh alert:

Host: ${agentName} (${agentIp})
Rule ID: ${ruleId} | Level: ${level}
Description: ${description}
Groups: ${groups}
Source IP: ${srcIp ?? 'N/A'}
Dest User: ${dstUser ?? 'N/A'} | Source User: ${srcUser ?? 'N/A'}
Command: ${command ?? 'N/A'}
Location (log file): ${location}
Timestamp: ${ts}

Full alert JSON:
${JSON.stringify(alert, null, 2)}`;

const claudeBodyObj = {
  model: cfg.claudeModel ?? 'claude-haiku-4-5-20251001',
  max_tokens: 700,
  system: systemPrompt,
  messages: [{ role: 'user', content: userPrompt }]
};

return [{
  json: {
    minAlertLevel: cfg.minAlertLevel,
    criticalLevel: cfg.criticalLevel,
    timezone: cfg.timezone,
    claudeModel: cfg.claudeModel,
    telegramBotToken: cfg.telegramBotToken,
    telegramChatId: cfg.telegramChatId,
    level,
    description,
    agentName,
    agentIp,
    srcIp,
    dstUser,
    srcUser,
    command,
    groups,
    ruleId,
    location,
    ts,
    isCritical,
    claudeBodyObj
  }
}];

const llmResponse = $input.first().json;
const alert = $('Extract Alert').item.json;

// Parse LLM JSON response. Supports Anthropic, OpenAI, and Ollama response shapes.
const rawText = llmResponse.content?.[0]?.text
  ?? llmResponse.choices?.[0]?.message?.content
  ?? llmResponse.message?.content
  ?? '{}';

let analysis = {};
try {
  const cleaned = rawText
    .replace(/^```json\s*/m, '')
    .replace(/^```\s*/m, '')
    .replace(/\s*```$/m, '')
    .trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = {
    risk_level: 'unknown',
    likely_cause: 'AI analysis unavailable, review alert manually.',
    is_likely_false_positive: false,
    fp_reason: '',
    recommended_action: ['Check Wazuh dashboard for full alert context'],
    investigate_commands: []
  };
}

// ============================================================
// CUSTOMIZE ME: Wazuh dashboard URL used in notification messages
// ============================================================
const dashboardUrl = 'https://your-wazuh-dashboard.example.com';
// ============================================================

const level = alert.level;
const riskEmojis = { critical: '🔴', high: '🟠', medium: '🟡', low: '🟢', unknown: '⚪' };
const alertEmoji = level >= 12 ? '🔴' : level >= 9 ? '🟠' : '🟡';
const alertLabel = level >= 12 ? 'CRITICAL' : level >= 9 ? 'HIGH' : 'WARNING';
const riskEmoji = riskEmojis[analysis.risk_level?.toLowerCase()] ?? '⚪';
const riskLabel = (analysis.risk_level ?? 'unknown').toUpperCase();

function buildMessage(platform) {
  const lines = [
    `${alertEmoji} *${alertLabel}* | Level ${level} | *${alert.agentName}*`,
    `*Rule:* ${alert.description}`,
  ];

  if (alert.srcIp) lines.push(`*Source IP:* ${alert.srcIp}`);
  if (alert.dstUser) lines.push(`*User:* ${alert.dstUser}`);
  if (alert.command) lines.push(`*Command:* \`${alert.command}\``);
  lines.push(`*Time:* ${alert.ts}`);

  lines.push('', `${riskEmoji} *AI: ${riskLabel}*`);
  lines.push(`${analysis.likely_cause}`);

  if (analysis.is_likely_false_positive) {
    lines.push(`⚠️ *Likely false positive*: ${analysis.fp_reason}`);
  }

  if ((analysis.recommended_action ?? []).length > 0) {
    lines.push('', '📋 *Actions:*');
    for (const a of analysis.recommended_action) {
      lines.push(`• ${a}`);
    }
  }

  if ((analysis.investigate_commands ?? []).length > 0) {
    lines.push('', '🔍 *Investigate:*');
    for (const cmd of analysis.investigate_commands) {
      lines.push(`\`${cmd}\``);
    }
  }

  const dashboardLink = platform === 'slack'
    ? `<${dashboardUrl}|Wazuh Dashboard>`
    : `[Wazuh Dashboard](${dashboardUrl})`;
  lines.push('', dashboardLink);

  return lines.join('\n');
}

return [{
  json: {
    slackMessage: buildMessage('slack'),
    telegramMessage: buildMessage('telegram'),
    level: alert.level,
    agentName: alert.agentName,
    riskLevel: analysis.risk_level
  }
}];
